const STEP = 1/60; let accumulator = 0; let last = performance.now();
function loop(now) {
  let dt = (now - last) / 1000; last = now;
  if (dt > 0.25) dt = 0.25;
  accumulator += dt;
  while (accumulator >= STEP) { update(STEP); accumulator -= STEP; }
  render(accumulator / STEP);
  requestAnimationFrame(loop);
}
